export meanMotion
"""\n    meanMotion(a::Number, μ::Number)\n\nComputes the Keplerian mean motion about a central body.\n\n# Arguments\n-`a::Number`: The semi-major axis of the orbit.\n-`μ::Number`: Standard graviational parameter of central body.\n\n# Returns\n- `n::Number`: The orbital mean motion.\n"""\nfunction meanMotion(a::Number, μ::Number)\n    return √(μ / (a^3.0))\nend\n\n"""\n    meanMotion(X::AstroCoord, μ::Number)\n\nComputes the Keplerian mean motion about a central body.\n\n# Arguments\n-`X::AstroCoord`: An coordinate set describing the orbit.\n-`μ::Number`: Standard graviational parameter of central body.\n\n# Returns\n- `n::Number`: The orbital mean motion.\n"""\nfunction meanMotion(X::AstroCoord, μ::Number)\n    kep = Keplerian(X, μ)\n    return meanMotion(kep.a, μ)\nend\n\n# Specialized methods for regularized coordinates\nfunction meanMotion(X::EDromo, μ::Number, ϕ::Number, config::RegularizedCoordinateConfig)\n    kep = Keplerian(X, μ, ϕ, config)\n    return meanMotion(kep.a, μ)\nend\n\nfunction meanMotion(X::KustaanheimoStiefel, μ::Number, config::RegularizedCoordinateConfig)\n    kep = Keplerian(X, μ, config)\n    return meanMotion(kep.a, μ)\nend\n\nfunction meanMotion(X::StiefelScheifele, μ::Number, ϕ::Number, config::RegularizedCoordinateConfig)\n    kep = Keplerian(X, μ, ϕ, config)\n    return meanMotion(kep.a, μ)\nend\n\nexport orbitalPeriod\n"""\n    orbitalPeriod(a::Number, μ::Number)\n\nComputes the Keplerian orbital period about a central body.\n\n# Arguments\n-`a::Number`: The semi-major axis of the orbit.\n-`μ::Number`: Standard graviational parameter of central body.\n\n# Returns\n-`T::Number`: The orbital period.\n"""\nfunction orbitalPeriod(a::Number, μ::Number)\n    return 2.0 * π / √(μ / (a^3.0))\nend\n\n"""\n    orbitalPeriod(X::AstroCoord, μ::Number)\n\nComputes the Keplerian orbital period about a central body.\n\n# Arguments\n-`X::AstroCoord`: An coordinate set describing the orbit.\n-`μ::Number`: Standard graviational parameter of central body.\n\n# Returns\n-`T::Number`: The orbital period.\n"""\nfunction orbitalPeriod(X::AstroCoord, μ::Number)\n    kep = Keplerian(X, μ)\n    return orbitalPeriod(kep.a, μ)\nend\n\n# Specialized methods for regularized coordinates\nfunction orbitalPeriod(X::EDromo, μ::Number, ϕ::Number, config::RegularizedCoordinateConfig)\n    kep = Keplerian(X, μ, ϕ, config)\n    return orbitalPeriod(kep.a, μ)\nend\n\nfunction orbitalPeriod(X::KustaanheimoStiefel, μ::Number, config::RegularizedCoordinateConfig)\n    kep = Keplerian(X, μ, config)\n    return orbitalPeriod(kep.a, μ)\nend\n\nfunction orbitalPeriod(X::StiefelScheifele, μ::Number, ϕ::Number, config::RegularizedCoordinateConfig)\n    kep = Keplerian(X, μ, ϕ, config)\n    return orbitalPeriod(kep.a, μ)\nend\n\nexport orbitalNRG\n"""\n    orbitalNRG(a::Number, μ::Number)\n\nComputes the keplerian orbital energy.\n\n# Arguments\n-`a::Number`: The semi-major axis of the orbit.\n-`μ::Number`: Standard graviational parameter of central body.\n\n# Returns\n-`NRG::Number`: The orbital energy. \n"""\nfunction orbitalNRG(a::Number, μ::Number)\n    return -μ / (2.0 * a)\nend\n\n"""\n    orbitalNRG(X::AstroCoord, μ::Number)\n\nComputes the keplerian orbital energy.\n\n# Arguments\n-`X::AstroCoord`: An coordinate set describing the orbit.\n-`μ::Number`: Standard graviational parameter of central body.\n\n# Returns\n-`NRG::Number`: The orbital energy. \n"""\nfunction orbitalNRG(X::AstroCoord, μ::Number)\n    kep = Keplerian(X, μ)\n    return orbitalNRG(kep.a, μ)\nend\n\n# Specialized methods for regularized coordinates\nfunction orbitalNRG(X::EDromo, μ::Number, ϕ::Number, config::RegularizedCoordinateConfig)\n    kep = Keplerian(X, μ, ϕ, config)\n    return orbitalNRG(kep.a, μ)\nend\n\nfunction orbitalNRG(X::KustaanheimoStiefel, μ::Number, config::RegularizedCoordinateConfig)\n    kep = Keplerian(X, μ, config)\n    return orbitalNRG(kep.a, μ)\nend\n\nfunction orbitalNRG(X::StiefelScheifele, μ::Number, ϕ::Number, config::RegularizedCoordinateConfig)\n    kep = Keplerian(X, μ, ϕ, config)\n    return orbitalNRG(kep.a, μ)\nend\n\nexport angularMomentumVector\n"""\n    angularMomentumVector(u::AbstractVector{<:Number})\n\nComputes the instantaneous angular momentum vector from a Cartesian state vector.\n\n# Arguments\n-`u::AbstractVector{<:Number}`: The Cartesian state vector [x; y; z; ẋ; ẏ; ż].\n\n# Returns\n-'angular_momentum::Vector{<:Number}': 3-Dimensional angular momentum vector.\n"""\nfunction angularMomentumVector(u::AbstractVector{<:Number})\n    r = SVector{3}(u[1], u[2], u[3])\n    v = SVector{3}(u[4], u[5], u[6])\n\n    return cross(r, v)\nend\n\n"""\n    angularMomentumVector(X::AstroCoord, μ::Number)\n\nComputes the instantaneous angular momentum vector from a Cartesian state vector.\n\n# Arguments\n-`X::AstroCoord`: An coordinate set describing the orbit.\n-`μ::Number`: Standard graviational parameter of central body.\n\n# Returns\n-`angular_momentum::Vector{<:Number}`: 3-Dimensional angular momentum vector.\n"""\nfunction angularMomentumVector(X::AstroCoord, μ::Number)\n    cart = Cartesian(X, μ)\n    return angularMomentumVector(params(cart))\nend\n\n# Specialized methods for regularized coordinates\nfunction angularMomentumVector(X::EDromo, μ::Number, ϕ::Number, config::RegularizedCoordinateConfig)\n    cart = Cartesian(X, μ, ϕ, config)\n    return angularMomentumVector(params(cart))\nend\n\nfunction angularMomentumVector(X::KustaanheimoStiefel, μ::Number, config::RegularizedCoordinateConfig)\n    cart = Cartesian(X, μ, config)\n    return angularMomentumVector(params(cart))\nend\n\nfunction angularMomentumVector(X::StiefelScheifele, μ::Number, ϕ::Number, config::RegularizedCoordinateConfig)\n    cart = Cartesian(X, μ, ϕ, config)\n    return angularMomentumVector(params(cart))\nend\n\nexport angularMomentumQuantity\n"""\n    angularMomentumQuantity(u::AbstractVector{<:Number})\n\nComputes the instantaneous angular momentum.\n\n# Arguments\n-`u::AbstractVector{<:Number}`: The Cartesian state vector [x; y; z; ẋ; ẏ; ż].\n\n# Returns\n-`angular_momentum::Number`: Angular momentum of the body.\n"""\nfunction angularMomentumQuantity(u::AbstractVector{<:Number})\n    return norm(angularMomentumVector(u))\nend\n\n"""\n    angularMomentumQuantity(X::AstroCoord, μ::Number)\n\nComputes the instantaneous angular momentum.\n\n# Arguments\n-`X::AstroCoord`: An coordinate set describing the orbit.\n-`μ::Number`: Standard graviational parameter of central body.\n\n# Returns\n-`angular_momentum::Number`: Angular momentum of the body.\n"""\nfunction angularMomentumQuantity(X::AstroCoord, μ::Number)\n    cart = Cartesian(X, μ)\n    return angularMomentumQuantity(params(cart))\nend\n\n# Specialized methods for regularized coordinates\nfunction angularMomentumQuantity(X::EDromo, μ::Number, ϕ::Number, config::RegularizedCoordinateConfig)\n    cart = Cartesian(X, μ, ϕ, config)\n    return angularMomentumQuantity(params(cart))\nend\n\nfunction angularMomentumQuantity(X::KustaanheimoStiefel, μ::Number, config::RegularizedCoordinateConfig)\n    cart = Cartesian(X, μ, config)\n    return angularMomentumQuantity(params(cart))\nend\n\nfunction angularMomentumQuantity(X::StiefelScheifele, μ::Number, ϕ::Number, config::RegularizedCoordinateConfig)\n    cart = Cartesian(X, μ, ϕ, config)\n    return angularMomentumQuantity(params(cart))\nend